@* Displays a single task card with move buttons *@

<div class="task-card">
    <div class="task-card-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    </div>
    <div class="task-card-body">
        <span class="task-assignee">👤 @Task.Assignee</span>
        <span class="task-due">📅 @Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-card-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn btn-sm btn-outline-secondary" @onclick="MoveLeft" disabled="@IsMoving">← Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn btn-sm btn-outline-secondary" @onclick="MoveRight" disabled="@IsMoving">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }

    private bool IsMoving;

    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    private async System.Threading.Tasks.Task MoveLeft()
    {
        var idx = Array.IndexOf(Statuses, Task.Status);
        if (idx > 0)
        {
            IsMoving = true;
            await OnMoveTask.InvokeAsync((Task.Id, Statuses[idx - 1]));
            IsMoving = false;
        }
    }

    private async System.Threading.Tasks.Task MoveRight()
    {
        var idx = Array.IndexOf(Statuses, Task.Status);
        if (idx < Statuses.Length - 1)
        {
            IsMoving = true;
            await OnMoveTask.InvokeAsync((Task.Id, Statuses[idx + 1]));
            IsMoving = false;
        }
    }
}

@* Inline form to create a new task within a column *@

<div class="add-task-form">
    <div class="mb-2">
        <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="Title" />
    </div>
    <div class="mb-2">
        <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="Assignee" />
    </div>
    <div class="mb-2">
        <select class="form-select form-select-sm" @bind="Priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="mb-2">
        <input type="date" class="form-control form-control-sm" @bind="DueDate" />
    </div>
    <div class="d-flex gap-2">
        <button class="btn btn-sm btn-primary" @onclick="Save" disabled="@IsSaving">Save</button>
        <button class="btn btn-sm btn-secondary" @onclick="Cancel" disabled="@IsSaving">Cancel</button>
    </div>
    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="text-danger mt-1 small">@ErrorMessage</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter, EditorRequired] public EventCallback OnCancel { get; set; }

    private string Title = string.Empty;
    private string Assignee = string.Empty;
    private string Priority = "Medium";
    private DateTime DueDate = DateTime.Today.AddDays(7);
    private bool IsSaving;
    private string? ErrorMessage;

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(Title) || string.IsNullOrWhiteSpace(Assignee))
        {
            ErrorMessage = "Title and Assignee are required.";
            return;
        }

        ErrorMessage = null;
        IsSaving = true;
        await OnSave.InvokeAsync((Title, Assignee, Priority, DueDate));
        IsSaving = false;
    }

    private async Task Cancel()
    {
        await OnCancel.InvokeAsync();
    }
}

@* A single Kanban column showing its tasks and an optional add-task form *@

<div class="kanban-column">
    <div class="kanban-column-header">
        <h5>@ColumnName</h5>
        <span class="badge bg-secondary">@Tasks.Count</span>
    </div>

    <div class="kanban-column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveTask="OnMoveTask" />
        }
    </div>

    <div class="kanban-column-footer">
        @if (_showForm)
        {
            <AddTaskForm OnSave="HandleSave" OnCancel="HideForm" />
        }
        else
        {
            <button class="btn btn-sm btn-outline-primary w-100" @onclick="ShowForm">+ Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = string.Empty;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = [];
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskAdded { get; set; }

    private bool _showForm;

    private void ShowForm() => _showForm = true;
    private void HideForm() => _showForm = false;

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) args)
    {
        await OnTaskAdded.InvokeAsync(args);
        _showForm = false;
    }
}

@* Search bar for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (_loading)
{
    <div class="d-flex justify-content-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error loading tasks:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="_allTasks" />

    <BoardSearchBar SearchText="@_searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="kanban-board d-flex gap-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="GetFilteredTasks("To Do")"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      OnMoveTask="HandleMoveTask"
                      OnTaskAdded="args => HandleAddTask("To Do", args)" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="GetFilteredTasks("In Progress")"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      OnMoveTask="HandleMoveTask"
                      OnTaskAdded="args => HandleAddTask("In Progress", args)" />

        <KanbanColumn ColumnName="Done"
                      Tasks="GetFilteredTasks("Done")"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      OnMoveTask="HandleMoveTask"
                      OnTaskAdded="args => HandleAddTask("Done", args)" />
    </div>
}

@code {
    private List<TaskItem> _allTasks = [];
    private string _searchText = string.Empty;
    private bool _loading = true;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        _loading = true;
        _error = null;
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private void HandleSearchChanged(string text)
    {
        _searchText = text;
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = _allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(_searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private async Task HandleMoveTask((int TaskId, string NewStatus) args)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
            var task = _allTasks.FirstOrDefault(t => t.Id == args.TaskId);
            if (task is not null)
            {
                _allTasks[_allTasks.IndexOf(task)] = task with { Status = args.NewStatus };
            }
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }

    private async Task HandleAddTask(string status, (string Title, string Assignee, string Priority, DateTime DueDate) args)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            _allTasks.Add(newTask with { Status = status });
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }
}

