@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (_loading)
{
    <div class="d-flex justify-content-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error loading tasks:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="_allTasks" />

    <BoardSearchBar SearchText="@_searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="kanban-board d-flex gap-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="GetFilteredTasks("To Do")"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      OnMoveTask="HandleMoveTask"
                      OnTaskAdded="args => HandleAddTask("To Do", args)" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="GetFilteredTasks("In Progress")"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      OnMoveTask="HandleMoveTask"
                      OnTaskAdded="args => HandleAddTask("In Progress", args)" />

        <KanbanColumn ColumnName="Done"
                      Tasks="GetFilteredTasks("Done")"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      OnMoveTask="HandleMoveTask"
                      OnTaskAdded="args => HandleAddTask("Done", args)" />
    </div>
}

@code {
    private List<TaskItem> _allTasks = [];
    private string _searchText = string.Empty;
    private bool _loading = true;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        _loading = true;
        _error = null;
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private void HandleSearchChanged(string text)
    {
        _searchText = text;
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = _allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(_searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private async Task HandleMoveTask((int TaskId, string NewStatus) args)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
            var task = _allTasks.FirstOrDefault(t => t.Id == args.TaskId);
            if (task is not null)
            {
                _allTasks[_allTasks.IndexOf(task)] = task with { Status = args.NewStatus };
            }
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }

    private async Task HandleAddTask(string status, (string Title, string Assignee, string Priority, DateTime DueDate) args)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            _allTasks.Add(newTask with { Status = status });
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }
}
"}

