    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }

    private bool IsMoving;

    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    private async System.Threading.Tasks.Task MoveLeft()
    {
        var idx = Array.IndexOf(Statuses, Task.Status);
        if (idx > 0)
        {
            IsMoving = true;
            await OnMoveTask.InvokeAsync((Task.Id, Statuses[idx - 1]));
            IsMoving = false;
        }
    }

    private async System.Threading.Tasks.Task MoveRight()
    {
        var idx = Array.IndexOf(Statuses, Task.Status);
        if (idx < Statuses.Length - 1)
        {
            IsMoving = true;
            await OnMoveTask.InvokeAsync((Task.Id, Statuses[idx + 1]));
            IsMoving = false;
        }
    }
}

