@* Inline form to create a new task within a column *@

<div class="add-task-form">
    <div class="mb-2">
        <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="Title" />
    </div>
    <div class="mb-2">
        <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="Assignee" />
    </div>
    <div class="mb-2">
        <select class="form-select form-select-sm" @bind="Priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="mb-2">
        <input type="date" class="form-control form-control-sm" @bind="DueDate" />
    </div>
    <div class="d-flex gap-2">
        <button class="btn btn-sm btn-primary" @onclick="Save" disabled="@IsSaving">Save</button>
        <button class="btn btn-sm btn-secondary" @onclick="Cancel" disabled="@IsSaving">Cancel</button>
    </div>
    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="text-danger mt-1 small">@ErrorMessage</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter, EditorRequired] public EventCallback OnCancel { get; set; }

    private string Title = string.Empty;
    private string Assignee = string.Empty;
    private string Priority = "Medium";
    private DateTime DueDate = DateTime.Today.AddDays(7);
    private bool IsSaving;
    private string? ErrorMessage;

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(Title) || string.IsNullOrWhiteSpace(Assignee))
        {
            ErrorMessage = "Title and Assignee are required.";
            return;
        }

        ErrorMessage = null;
        IsSaving = true;
        await OnSave.InvokeAsync((Title, Assignee, Priority, DueDate));
        IsSaving = false;
    }

    private async Task Cancel()
    {
        await OnCancel.InvokeAsync();
    }
}

