@* A single Kanban column showing its tasks and an optional add-task form *@

<div class="kanban-column">
    <div class="kanban-column-header">
        <h5>@ColumnName</h5>
        <span class="badge bg-secondary">@Tasks.Count</span>
    </div>

    <div class="kanban-column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveTask="OnMoveTask" />
        }
    </div>

    <div class="kanban-column-footer">
        @if (_showForm)
        {
            <AddTaskForm OnSave="HandleSave" OnCancel="HideForm" />
        }
        else
        {
            <button class="btn btn-sm btn-outline-primary w-100" @onclick="ShowForm">+ Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = string.Empty;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = [];
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskAdded { get; set; }

    private bool _showForm;

    private void ShowForm() => _showForm = true;
    private void HideForm() => _showForm = false;

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) args)
    {
        await OnTaskAdded.InvokeAsync(args);
        _showForm = false;
    }
}

